#include <stdio.h>
int main() {
    int T, X, Y, Z;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &X, &Y, &Z);
        int B[X][Y][Z], A[X][Y][Z];
        for (int i = 0; i < X; i++) {
            for (int j = 0; j < Y; j++) {
                for (int k = 0; k < Z; k++) {
                    scanf("%d", &B[i][j][k]);
                }
            }
        }
        for (int i = 0; i < X; i++) {
            for (int j = 0; j < Y; j++) {
                for (int k = 0; k < Z; k++) {
                    if (i == 0 && j == 0 && k == 0) {
                        A[i][j][k] = B[i][j][k];
                    } else if (i == 0 && j == 0) {
                        A[i][j][k] = B[i][j][k] - B[i][j][k-1];
                    } else if (i == 0 && k == 0) {
                        A[i][j][k] = B[i][j][k] - B[i][j-1][k];
                    } else if (j == 0 && k == 0) {
                        A[i][j][k] = B[i][j][k] - B[i-1][j][k];
                    } else if (i == 0) {
                        A[i][j][k] = B[i][j][k] - B[i][j][k-1] - B[i][j-1][k] + B[i][j-1][k-1];
                    } else if (j == 0) {
                        A[i][j][k] = B[i][j][k] - B[i][j][k-1] - B[i-1][j][k] + B[i-1][j][k-1];
                    } else if (k == 0) {
                        A[i][j][k] = B[i][j][k] - B[i][j-1][k] - B[i-1][j][k] + B[i-1][j-1][k];
                    } else {
                        A[i][j][k] = B[i][j][k] - B[i][j][k-1] - B[i][j-1][k] - B[i-1][j][k] + B[i-1][j][k-1] + B[i][j-1][k-1] + B[i-1][j-1][k] - B[i-1][j-1][k-1];
                    }
                }
            }
        }
        for (int i = 0; i < X; i++) {
            for (int j = 0; j < Y; j++) {
                for (int k = 0; k < Z; k++) {
                    printf("%d ", A[i][j][k]);
                }
                printf("\n");
            }
        }
    }
    return 0;
}

